var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"흠~ 흐음~ 흠~","JPN":"ふん～ふふん～ふん～","ENG":"*Humming*","TWN":"哼～哼哼～哼～"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후후, 옳지~ 다들 가축처럼 넙죽 엎드려서 짖으렴!","JPN":"うふふ、よしよし～家畜のようにひれ伏して吠えなさい！","ENG":"Fu fuu, that's right...! Get down on your knees and bark like livestock!","TWN":"呵呵呵，沒錯～大家像畜生一樣在地上爬吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그리고 가서 내 원본을 찾는 거야.","JPN":"そして私のオリジナルを探し出すのよ。","ENG":"And go find my original.","TWN":"接下來，帶我去找本體吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"이 참을 수 없는 공복감을 채워 줄 수 있는 건, 내 원본 밖에 없으니까.","JPN":"この耐えがたい空腹感を満たすことができるのは、オリジナルしかいないから。","ENG":"The only thing that can satiate this unbearable hunger is the original.","TWN":"唯一能夠滿足這股難以忍受的饑餓的，只有我的本體了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"목숨만 붙어있으면 되니까, 팔 다리는 마음대로 해도 돼.","JPN":"手足は好きにしてもいいわ。息さえしていればいいの。","ENG":"As long as you bring her to me alive, do whatever you want with her limbs.","TWN":"只要能把她活著帶回來，要斷手斷腳都可以。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"제길, 그림자가 침식파로 하위 침식체를 장악하여 조종하고 있다!","JPN":"くそ、シャドウが侵食波で下位侵食体を操っている！","ENG":"Gah, the Shadow is controlling the lower C.O.s with Corruption rays!","TWN":"可惡，暗影正在透過侵蝕波，控制低階侵蝕體！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"방패를 들고, 모두 대열을 유지해!","JPN":"盾を持ち、隊列を維持せよ！","ENG":"Raise your shields and maintain formation!","TWN":"舉起盾牌，所有人保持陣列！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"침식체가 대열 사이에 파고들지 못하도록 막아!","JPN":"侵食体が隊列に割り込めないように防げ！","ENG":"Stop the C.O.s from squirming pass our ranks!","TWN":"抵擋低階侵蝕體的衝擊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"지금이다! 전대원, 사격 개시!","JPN":"今だ！　全隊員、射撃開始！","ENG":"NOW! All units, fire!","TWN":"就是現在！戰隊員，開火！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"잔챙이들을 제압해! 그림자의 요격은 야크샤 전대에게 맡긴다!","JPN":"雑魚を制圧しろ！　シャドウの迎撃はヤクシャー戦隊に任せる！","ENG":"Kill the small pests! The Yaksha Division will be in charge of taking down the Shadow!","TWN":"壓制住那些傢伙！暗影就交給夜叉戰隊阻擊了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어머, 역시 이 시대의 관리국은 만만하지 않네.","JPN":"あら、やっぱりこの時代の管理局はおいそれといかないわね。","ENG":"Oh, my. The Administration of this era isn't easy.","TWN":"喔，喔……，這個時代的管理局真不簡單啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"다들 군기가 딱 잡혔어.","JPN":"軍紀がしっかりしてるわ。","ENG":"They're so organized and disciplined.","TWN":"軍紀嚴明。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗, 하지만……!","JPN":"うふふ、でも……！","ENG":"Fu fuu, but...!","TWN":"呵呵呵，不過嘛……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 쏘지 마! 아군이다!","JPN":"くそ！　撃つな！　味方だ！","ENG":"Dammit! Cease fire! It's an ally!","TWN":"該死！別開槍！是友軍！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"똑바로 서 있을 수가 없어! 균형을 못 잡겠어!","JPN":"まともに立っていられない！　バランスが崩れる！","ENG":"I can't stand upright! I can't keep my balance!","TWN":"我站不起來了啊！沒辦法保持平衡！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"진정해! 적에게 현혹되지 말라고!!","JPN":"落ち着け！　敵に惑わされるな！","ENG":"Calm down! Don't be fooled by the enemy!","TWN":"冷靜下來！不要被敵人欺騙了！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아하하하하하하핫……!!","JPN":"あはははははは……！！","ENG":"AH HAHAHAHAHA...!!","TWN":"啊哈哈哈哈哈……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"기분 최고네! 이렇게……! 이런 식으로 다시 기회를 얻게 될 줄이야……!","JPN":"最高の気分だわ……！　こうして……またチャンスが巡ってくるなんて……！","ENG":"This feels wonderful! I never thought that I'd get another chance like this...!","TWN":"感覺棒極了！像這樣……！沒想到我還能有這樣的機會……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그러니 어서……! 어서 원본을 잡아먹고 더 완전해져야만 해!","JPN":"だから早く……！　オリジナルを喰べて、完全体にならないと！","ENG":"And now...! I just need to consume the original and become more complete!","TWN":"所以快點吧……！讓我吞掉你，變得更加完整！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그렇게 되면……!!","JPN":"そうすれば……！！","ENG":"Then...!!","TWN":"這樣一來……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장, 저기 보인다……! 저게 그림자라는 녀석이야……!?","JPN":"くそ……見えるぞ……！　あれがシャドウってやつなのか……！？","ENG":"Gah, I see the Shadow...! That's...?!","TWN":"該死，看那裡……！那傢伙就是暗影……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 저 녀석의 얼굴……!!","JPN":"待て、あいつの顔……！！","ENG":"Wait... her face...!!","TWN":"等等，那傢伙的臉……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나랑 똑같이 생겼잖아! 꼬리랑 귀도 있어!","JPN":"アタシとそっくりじゃないか！　耳と尻尾もある！","ENG":"She looks exactly like me! Even with the ears and tail!","TWN":"她長得和我一模一樣！連尾巴和耳朵也是！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그야 도플갱어 타입이니까, 너랑 얼굴이 같을 수밖에.","JPN":"それはもちろん、ドッペルゲンガータイプだからね。あなたと同じでしょう。","ENG":"That's because she's a Doppelganger-type. So she has the same appearance as you.","TWN":"因為它是二重身類型的侵蝕體，自然和你長得一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"근데 복장이 저게 뭐야? 누가 옷을 저렇게 야시시하게 입는다고!!","JPN":"ていうか、なんだよあの服は！　あんな破廉恥な服アタシは着ないぞ！","ENG":"But what's that she's wearing? Who would want to wear something so revealing?!","TWN":"那是什麼衣服？誰會把衣服穿得這麼暴露！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐? 야시시하다고……?","JPN":"え？　破廉恥な服……？","ENG":"What? Revealing...?","TWN":"什麼？暴露…… ？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"잠깐, 저 악기는……!?","JPN":"ちょっと、あの楽器は……！？","ENG":"Wait, that instrument is...?!","TWN":"等等，那個樂器是……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"탐지기에 침식파 타입도 도플갱어로 찍히긴 하는데…… 뭔가 이상하네.","JPN":"探知機にも、ドッペルゲンガータイプの侵食波が認識されているけど……何かおかしい。","ENG":"The detector's Corruption ray type is also picking up as a Doppelganger... but something's not right.","TWN":"奇怪……不管是侵蝕波類型，還是探測器上顯示的都是二重身……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어째서 <color=#ffd34c>엘리시움</color>의 그림자가 나타난 거지?","JPN":"どうして<color=#ffd34c>エリシウム</color>のシャドウが現れたの？","ENG":"What is an <color=#ffd34c>Elysium</color> Shadow doing here?","TWN":"為什麼會出現<color=#ffd34c>愛樂組織</color>的暗影？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"엘리시움?","JPN":"エリシウム？","ENG":"Elysium?","TWN":"愛樂組織？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"기다리고 있었습니다! 부전대장님!","JPN":"お待ちしておりました、副戦隊長！","ENG":"We've been waiting for you! Deputy Commander!","TWN":"我們一直在等你！副戰隊長！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"현재, 관리국 지원병력이 최선을 다해 4종 침식체를 막아서고 있습니다만.","JPN":"現在、管理局の支援兵力が総力を尽くして第4種侵食体に対抗していますが……","ENG":"The Administration's support troops are currently doing their best to stop the Category 4 C.O.","TWN":"目前，管理局支援的兵力正在全力阻擊4類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"엘리시움의 특성상, 일반병력으로는 공략이 무척 어렵습니다.","JPN":"エリシウムの特性上、一般兵力で攻略するのはかなり厳しいです。","ENG":"But ordinary troops won't cut it because it is an Elysium.","TWN":"但由於愛樂組織的特性，普通兵力很難對其造成傷害。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"지휘를 부탁드리겠습니다. 야크샤 부전대장님!","JPN":"指揮をお願いします、ヤクシャー副戦隊長！","ENG":"I leave you in charge, Yaksha Deputy Commander!","TWN":"就拜託你來指揮了。夜叉副戰隊長！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야, 잠깐! 엘리시움의 그림자가 뭔데?","JPN":"おい、待て！　エリシウムのシャドウって何なんだ？","ENG":"Hey, wait! What's an Elysium Shadow?","TWN":"喂，等等！愛樂組織的暗影是什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그림자는 데몬 타입이랑 도플갱어 타입만 있는 거 아니었어?","JPN":"シャドウはデーモンタイプとドッペルゲンガータイプだけじゃなかったのか？","ENG":"Weren't there only supposed to be Demon and Doppelganger-type Shadows?","TWN":"不是只有惡魔型和二重身型暗影嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"데몬 타입이야. 원래라면 특수한 아티팩트를 매개로 침식되어 발생하는 상위종 침식체지.","JPN":"デーモンタイプよ。本来は、特殊なアーティファクトを媒介にして侵食し、発生する上異種の侵食体ね。","ENG":"She's a Demon-type. Originally, she was a high-tier C.O. who was corrupted with a special Artifact.","TWN":"愛樂組織都是惡魔型的暗影。是一種以特殊的人造神器為媒介，被侵蝕而誕生的高級侵蝕體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"악기로 인간의 정신을 헤집어 놓는 까다로운 녀석들이야.","JPN":"楽器で人間の精神を錯乱させる厄介な奴らよ。","ENG":"The Elysium are tricky to deal with as they can stir up the minds of humans with their instruments.","TWN":"他們都是些難纏的傢伙，會用樂器撥弄人類的精神。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"인간의 정신을 헤집는다고?","JPN":"人間の精神を錯乱させる？","ENG":"Stir up the minds of humans?","TWN":"撥弄人類的精神？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 아무래도 이건 좀 특별한 케이스인 것 같은데?","JPN":"でも、どうやら今回はかなり特殊なケースのようね。","ENG":"I believe this one to be a bit of a special case.","TWN":"但我想這只有些特例，對吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"누가봐도 도플갱어 타입인데, 데몬 타입의 성질도 가지고 있어. 이런 건 나도 처음 봐!","JPN":"どうみてもドッペルゲンガータイプなのに、デーモンタイプの性質を持ち合わせている。こんなのは私も初めて見る……！","ENG":"I've never seen one like this either! She's a Doppelganger-type, but also has properties of a Demon-type.","TWN":"她怎麼看都是二重身型，但同時又具備惡魔型的特徵。這是我第一次看到這樣的事情！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 이면세계에서는 무슨 일이 일어나도 이상하지 않다는 건가……?","JPN":"やっぱり、裏世界では何が起きてもおかしくないのね。","ENG":"So this is what you meant by anything can happen in Counterside.","TWN":"畢竟，異界無論發生什麼都不奇怪……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아무튼 저 망할 그림자가 나 때문에 생겼다는 거잖아!","JPN":"とにかくあのくそシャドウはアタシのせいで発生したんだろう！","ENG":"Anyway, that Shadow is here because of me, right?!","TWN":"不管怎麼樣，那個該死的暗影是因我而生的，對吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길, 그럼 내가 가서 책임을 져야 해!","JPN":"じゃあ、アタシが責任を取るしかない！","ENG":"Dammit, I need to go take care of it then!","TWN":"可惡，這是我該負的責任！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나 때문에 눈앞에서 또 누군가가 죽는 꼴은 보고 싶지 않아!","JPN":"自分のせいで誰かが死ぬなんて、もう二度と見たくないんだ！","ENG":"I don't want to see another person die because of me!","TWN":"我不想再看到有人因為我而死在我的面前了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무엇보다도…… 내 얼굴로 저런 짓을 하는 게 마음에 안 든다고……!!","JPN":"なにより……アタシの顔をしてあんなことをやってるのが気に食わない……！！","ENG":"And above all else... I don't like it that she's doing all this with the same face as me...!!","TWN":"最重要的是……我不想看到她用我的臉做出那種事情……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"잠깐, 기다려. 길고양이!","JPN":"ちょ、待ちなさい、野良猫！","ENG":"Wait. Stop right there, stray cat!","TWN":"等等，等一下。流浪貓！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 어쩔 수 없네.","JPN":"はあ……仕方ないね。","ENG":"*Sigh* Guess there's no stopping her.","TWN":"哀，沒辦法了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어때? 다들 내 품에 안겨 볼래?","JPN":"どうかしら？　みんな私の胸に抱かれてみない？","ENG":"So, would you all like to be held in my arms?","TWN":"如何？你們都願意被我抱在懷裡嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"기쁨도, 슬픔도 전부 다 잊고 배를 보이면서 죽을 때까지 복종하는 거야.","JPN":"喜びも悲しみもぜんぶ忘れて、無防備な姿で死ぬまで服従するのよ。","ENG":"Forget all your joys and sorrows. Show your belly and obey me until death.","TWN":"忘卻一切悲歡離合，露出柔軟的腹部，順從至死。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"唔？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"……큿!?","JPN":"……くぅっ！？","ENG":"...Kgh?!","TWN":"……咳？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"개소리 집어치워! 누가 누구한테 복종한다는 거야!","JPN":"ふざけたことぬかすな！　誰が誰に服従するってんだ！","ENG":"Cut the crap! No one's obeying you!","TWN":"廢話少說！要誰順從你！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어머? 원본이 제발로 굴러들어왔잖아?","JPN":"あら、オリジナルが自ら飛び込んで来たわ。","ENG":"Oh? Looks like the original just came to me on her own!","TWN":"喔？本體已經出現了呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"원본?","JPN":"オリジナル？","ENG":"Original?","TWN":"本體？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후후훗! 아하하하하하하하하핫……!!","JPN":"うふふふっ！　あはははははははは……！！","ENG":"U fu fu fuu! AH HAHAHAHAHAHA...!!","TWN":"呵呵呵！哈哈哈哈哈哈……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그래……! 눈을 뜨자마자 직감할 수 있었거든……!","JPN":"そうよ……！　目覚めた瞬間感じたわ……！","ENG":"Yes...! I instinctively knew the second I opened my eyes...!","TWN":"沒錯……！當我睜開眼睛的時候，我就感覺到了……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그 찢어 죽일 마에스트로에게 핵을 만져진 뒤에 표류하던 잔류사념이…….","JPN":"あの憎たらしいマエストロに核を触られた後、漂流し続けていた私の残留思念が……","ENG":"My lingering will that drifted after that wench Maestra touched my core...","TWN":"被指揮家奪去核心後殘留的思緒……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"지금 이 세계의 환경과 네 육체를 매개로 발생한 도플갱어에게 깃들게 된 거야!","JPN":"この世界の環境と君の肉体を媒介に発生したドッペルゲンガーに宿ったの！","ENG":"has possessed the Doppelganger that was created by using this environment and your body as a catalyst!","TWN":"附在了以現在這個世界的環境，和你的身體為媒介所創造出來的二重身身上！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"신기하지 않니?","JPN":"不思議だと思わない？","ENG":"Isn't that amazing?","TWN":"是不是很神奇？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"이렇게 시간과…… 공간을 초월해서 내가 존재할 수 있다는 게 말이야……!!","JPN":"時間も空間も超越して、私が今ここに存在できる事実が……！！","ENG":"That I can exist... beyond time and space...!!","TWN":"這樣超越時間和……空間的存在……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 소리하는지 하나도 모르겠거든!","JPN":"何言ってるのかさっぱりわからないな！","ENG":"I have no idea what you're talking about!","TWN":"我不知道你在說什麼！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니까 얌전히 뒈지라고, 이 망할 괴물아……!!","JPN":"だから大人しくくたばりやがれ、このくそ化け物……！！","ENG":"So shut up and just die, you damn monster...!!","TWN":"老實點吧，你這個該死的怪物……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗, 역시 생각대로 야만스럽게 힘만 세구나?","JPN":"うふふ、やっぱり。バカ力の野蛮人なのね。","ENG":"Fu fuu. You're just as barbarically strong as I thought you'd be.","TWN":"呵呵呵，不出所料，你果然只會用蠻力嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"내가 그 근육투성이 몸을 내 마음에 들게 가꾸는데 얼마나 힘들었는 줄 알아?","JPN":"その筋肉でがちがちの体を、私好みに作り変えるのにどれだけ苦労したと思ってるの。","ENG":"Do you know how difficult it was for me to shape that brute of a body to my liking?","TWN":"你知道我把那肌肉發達的身材塑造成自己喜歡的樣子有多難嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐라고……!?","JPN":"何だと……！？","ENG":"What...?!","TWN":"你說什麼？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내 근육이 뭐가 어쨌다고!! 이 몸을 만드는데 웨이트를 얼마나 열심히 했는데!!","JPN":"アタシの筋肉に文句言うのか！！　ここまで鍛え上げるのに、どれだけ筋トレを頑張ったと思ってるんだ！！","ENG":"What about my muscles?! I trained hard and lifted heavy weights to get my physique!","TWN":"我的肌肉怎麼了！！為了塑造這樣的身材，我可是付出了很多努力的！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그래도 다행이라고 생각해.","JPN":"でもよかったと思ってる。","ENG":"But still, I think of myself as being fortunate.","TWN":"不過我很慶倖。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"여기서 <color=#ffd34c>육체의 원본</color>인 널 잡아먹으면, 그런 쓸데없는 노력을 다시 할 필요는 없겠지.","JPN":"ここで<color=#ffd34c>肉体のオリジナル</color>である君を喰べたら、そんな無駄な努力を二度とする必要はなくなる。","ENG":"Because if I consume <color=#ffd34c>the body of the original</color> here, I won't need to go through such vain efforts.","TWN":"如果我在這裡吞噬了<color=#ffd34c>本體</color>，就不用再白費力氣了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그리고 필하모닉 홀에 있는 <color=#ffd34c>핵의 원본</color>까지 흡수하게 되면……!","JPN":"そしてフィルハーモニーホールにある<color=#ffd34c>核のオリジナル</color>まで吸収したら……！","ENG":"And if I can absorb <color=#ffd34c>the original core</color> that's in Philharmonic Hall...!","TWN":"然後，再吸收掉管弦樂廳裡的<color=#ffd34c>本體核心</color>……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후후, 그때야말로……!","JPN":"うふふ、その時には……！","ENG":"Fu fuu fuu, then I'll be...!","TWN":"呵呵呵，那個時候……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그 증오스러운 네퀴티아를 찢어죽이고, 내가 최고 지휘자에 오를 수 있겠지!","JPN":"あの憎たらしいネキティアを八つ裂きにして、私がマエストロになるの！","ENG":"I'll be able to tear that wretched Nequitia apart and become the Chief Conductor myself!","TWN":"我就能撕爛那個可惡的莉奎蒂亞，登上首席指揮家的位置！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"가능한 일이야……! 미래에 대한 정보를 알고 있는 지금의 나라면 충분히…… ","JPN":"できるわ……！　未来の情報を知っている今の私なら、十分…… ","ENG":"It's possible...! Since I know what'll happen in the future, it's more than enough–","TWN":"這是可能的……！如果是知道了未來的我的話……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"으읏!?","JPN":"ううっ！？","ENG":"Ngh?!","TWN":"呃嗚？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"형태는 클리파 에너지에 의해 구성된 허깨비라고 해도…….","JPN":"形こそクリファエネルギーによって構成されたまがい物とはいえ……","ENG":"Even if you're just an illusion created by the Qlipha energy...","TWN":"哪怕那個形態是逆卡巴拉能量所創造的鬼影……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결국, 그 본질은 엘리시움의 그림자랑 다를 바 없나 봐?","JPN":"本質はエリシウムのシャドウと変わらないのね。","ENG":"in the end, your essence is still the same as an Elysium Shadow, no?","TWN":"說到底，你的本質和愛樂組織的暗影沒什麼不同吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"오랜만에 진심으로 해야겠네.","JPN":"久しぶりに本気を出さないと。","ENG":"I guess I get to flex my powers for a bit today.","TWN":"我已經很長時間沒有認真了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야, 토끼녀! 왜 이렇게 늦었어?","JPN":"なんだよ、ウサギ女！　遅かったじゃないか！","ENG":"Huh? Bunny ears! What took you so long?","TWN":"什麼啊，兔耳朵！為什麼這麼晚？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"길고양이, 싸우기 전에 하나 물어보고 싶은 게 있는데","JPN":"野良猫、戦う前に一つ確認したいんだけど。","ENG":"Stray cat, I want to ask you a question before the fight.","TWN":"流浪貓，在戰鬥之前，我想問你一件事。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭔데, 중요한 거야?","JPN":"何だ、重要なことか？","ENG":"What? Is it something important?","TWN":"什麼，很重要嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"너 혹시 음악 같은 거 좋아하니? 클래식 같은 거 말이야.","JPN":"あなた、音楽は好き？　クラシックとか。","ENG":"Do you like music by chance? Classical music, that is.","TWN":"你喜歡音樂嗎？就是那種古典音樂。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐……!?","JPN":"はあ……！？","ENG":"Huh...?!","TWN":"啊……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"갑자기 무슨 뚱딴지 같은 소리야?","JPN":"急に何わけわかんないこと言ってんだ？","ENG":"Why are you suddenly asking me this nonsense?","TWN":"你突然胡說些什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};